import{_ as p}from"./plugin-vue_export-helper-DlAUqK2U.js";import{e as t,g as s,f as l,i as o,h as a,j as c,r as i,o as r}from"./app-_JojGnWZ.js";const u="/assets/0199805b-363c-76b8-a88c-0d307a53446c-CereLJz_.png",d="/assets/0199805c-69d0-74bc-b991-4a169fcdeec9-BOwpf3es.png",m="/assets/0199805f-872d-72cd-870a-570b3f07aa0a-oMuTDB52.png",k={};function v(b,n){const e=i("RouteLink");return r(),t("div",null,[n[2]||(n[2]=s("h1",{id:"gcs-editor-extensions-igameplaycamerasystemhost",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#gcs-editor-extensions-igameplaycamerasystemhost"},[s("span",null,"GCS Editor Extensions & IGameplayCameraSystemHost")])],-1)),s("p",null,[o(e,{to:"/GameEngine/Unreal/Camera/02-getting-started-gcs.html"},{default:c(()=>n[0]||(n[0]=[a("第一篇文章")])),_:1}),n[1]||(n[1]=a("中我们简单介绍了GCS怎么激活，以及怎么在编辑器中利用它的工具链去构建对应行为的摄像机。"))]),n[3]||(n[3]=l('<p>这篇文章主要介绍工具链中的UCameraAsset是怎么可以创建模版资源的，以及它是怎么指定CameraDirector的。</p><p>文章的后面部分我们还会对GCS的核心接口 IGameplayCameraSystemHost 进行介绍。</p><h2 id="uproperty-instanced" tabindex="-1"><a class="header-anchor" href="#uproperty-instanced"><span>UPROPERTY(Instanced)</span></a></h2><p>我们首先要介绍的UProperty的Instanced标签，官网对这个标签的介绍是：</p><figure><img src="'+u+`" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>简单来说就是当父对象被实例化或复制时，会为该属性自动创建独立的子对象实例。</p><h3 id="典型对比示例" tabindex="-1"><a class="header-anchor" href="#典型对比示例"><span>典型对比示例</span></a></h3><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token comment">// 纹理资产，多个对象共享同一个纹理资源</span></span>
<span class="line"><span class="token function">UPROPERTY</span><span class="token punctuation">(</span>Category<span class="token operator">=</span>Test<span class="token punctuation">,</span> EditDefaultsOnly<span class="token punctuation">)</span></span>
<span class="line">UTexture2D<span class="token operator">*</span> TestAsset<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 组件，多个对象需要各自独立的组件实例</span></span>
<span class="line"><span class="token function">UPROPERTY</span><span class="token punctuation">(</span>Category<span class="token operator">=</span>Test<span class="token punctuation">,</span> EditDefaultsOnly<span class="token punctuation">)</span></span>
<span class="line">UStaticMeshComponent<span class="token operator">*</span> TestComponent<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>​TestAsset​ 指向的是一个“共享的”资源（纹理），多个 actor 可以共享同一个纹理资源指针，内存节省且合理。</li><li>​TestComponent​ 是 actor 的子对象，每个 actor 需要单独的组件实例（对象），否则组件状态会冲突。</li></ul><p>这个区别就是通过 Instanced​ 标签体现的：</p><ul><li><p>纹理属性不需要加 Instanced​，就是共享指针。</p></li><li><p>组件属性则需要加 Instanced​，表示每个包含它的对象中，都会实例化不同的组件对象。</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token comment">/** The main skeletal mesh associated with this Character (optional sub-object). */</span></span>
<span class="line"><span class="token function">UPROPERTY</span><span class="token punctuation">(</span>Category<span class="token operator">=</span>Character<span class="token punctuation">,</span> VisibleAnywhere<span class="token punctuation">,</span> BlueprintReadOnly<span class="token punctuation">,</span> meta<span class="token operator">=</span><span class="token punctuation">(</span>AllowPrivateAccess <span class="token operator">=</span> <span class="token string">&quot;true&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">TObjectPtr<span class="token operator">&lt;</span>USkeletalMeshComponent<span class="token operator">&gt;</span> Mesh<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 上面的Instanced表述主要介绍这个标签的用法，实际上从ACharacter的Mesh组件来看，它是内部控制实例化的，蓝图层面只允许私有只读访问。</span></span>
<span class="line"><span class="token comment">// 是否需要添加Instanced标签是根据实际需求来进行的，下面会进行说明。</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul><h3 id="实例说明" tabindex="-1"><a class="header-anchor" href="#实例说明"><span>实例说明</span></a></h3><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token function">UCLASS</span><span class="token punctuation">(</span>MinimalAPI<span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">UCameraAsset</span> <span class="token operator">:</span> <span class="token base-clause"><span class="token keyword">public</span> <span class="token class-name">UObject</span></span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">private</span><span class="token operator">:</span></span>
<span class="line">	<span class="token comment">/** The camera director to use in this camera. */</span></span>
<span class="line">	<span class="token function">UPROPERTY</span><span class="token punctuation">(</span>Instanced<span class="token punctuation">)</span></span>
<span class="line">	TObjectPtr<span class="token operator">&lt;</span>UCameraDirector<span class="token operator">&gt;</span> CameraDirector<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token function">UCLASS</span><span class="token punctuation">(</span>MinimalAPI<span class="token punctuation">,</span> EditInlineNew<span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">UBlueprintCameraDirector</span> <span class="token operator">:</span> <span class="token base-clause"><span class="token keyword">public</span> <span class="token class-name">UCameraDirector</span></span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">	<span class="token comment">/** The blueprint class that we should instantiate and run. */</span></span>
<span class="line">	<span class="token function">UPROPERTY</span><span class="token punctuation">(</span>EditAnywhere<span class="token punctuation">,</span> Category<span class="token operator">=</span><span class="token string">&quot;Evaluation&quot;</span><span class="token punctuation">)</span></span>
<span class="line">	TSubclassOf<span class="token operator">&lt;</span>UBlueprintCameraDirectorEvaluator<span class="token operator">&gt;</span> CameraDirectorEvaluatorClass<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>每个CameraAsset实例化的时候都会创建自己的CameraDirector实例。</li><li>CameraDirector的子类添加了EditInlineNew标签，这样它标记为可编辑的属性，可以在蓝图配置中进行剪辑。</li></ul><p>编辑器中的实际创建效果如下：</p><figure><img src="`+d+`" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="ucameraasseteditor-uasseteditor" tabindex="-1"><a class="header-anchor" href="#ucameraasseteditor-uasseteditor"><span>UCameraAssetEditor(UAssetEditor)</span></a></h2><p>​UAssetEditor​ 是编辑器中处理特定资产编辑流程的基类.</p><ul><li>​UAssetEditor​ 管理资产编辑器窗口生命周期、标签页，调用 Toolkit 实现 UI 逻辑</li><li>当用户点击内容浏览器中的某个资产时，如果有对应的 UAssetEditor​，编辑器会创建实例打开该资产。</li></ul><p>UCameraAsset 通过自定义的资产编辑器 UCameraAssetEditor 在编辑器中实现了类似 UDataAsset 的资产编辑功能。</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token comment">/**</span>
<span class="line"> * Base class for all asset editors.</span>
<span class="line"> */</span></span>
<span class="line"><span class="token function">UCLASS</span><span class="token punctuation">(</span>Abstract<span class="token punctuation">,</span> MinimalAPI<span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">UAssetEditor</span> <span class="token operator">:</span> <span class="token base-clause"><span class="token keyword">public</span> <span class="token class-name">UObject</span><span class="token punctuation">,</span> <span class="token keyword">public</span> <span class="token class-name">IAssetEditorInstance</span>；</span>
<span class="line"></span>
<span class="line"><span class="token comment">/**</span>
<span class="line"> * Editor for a camera asset.</span>
<span class="line"> */</span></span>
<span class="line"><span class="token function">UCLASS</span><span class="token punctuation">(</span><span class="token class-name">Transient</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">UCameraAssetEditor</span> <span class="token operator">:</span> <span class="token keyword">public</span> <span class="token class-name">UAssetEditor</span></span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">	<span class="token keyword">void</span> <span class="token function">Initialize</span><span class="token punctuation">(</span>TObjectPtr<span class="token operator">&lt;</span>UCameraAsset<span class="token operator">&gt;</span> InCameraAsset<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">	<span class="token comment">// UAssetEditor interface</span></span>
<span class="line">	<span class="token keyword">virtual</span> <span class="token keyword">void</span> <span class="token function">GetObjectsToEdit</span><span class="token punctuation">(</span>TArray<span class="token operator">&lt;</span>UObject<span class="token operator">*</span><span class="token operator">&gt;</span><span class="token operator">&amp;</span> InObjectsToEdit<span class="token punctuation">)</span> <span class="token keyword">override</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">virtual</span> TSharedPtr<span class="token operator">&lt;</span>FBaseAssetToolkit<span class="token operator">&gt;</span> <span class="token function">CreateToolkit</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">override</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">private</span><span class="token operator">:</span></span>
<span class="line">	<span class="token function">UPROPERTY</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">	TObjectPtr<span class="token operator">&lt;</span>UCameraAsset<span class="token operator">&gt;</span> CameraAsset<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>​UCameraAssetEditor​ 继承自 UAssetEditor​，负责CameraAsset的编辑功能。</p><ul><li><p>通过覆写接口，指定了编辑器工具FCameraAssetEditorToolkit​， 以及编辑对象 CameraAsset​。</p></li><li><p>​FCameraAssetEditorToolkit​实现了编辑器 UI 和逻辑：</p><ul><li>树状视图、属性面板、视窗等编辑界面。</li><li>通过 DataBinding 和事件机制响应用户操作，修改资产内容。</li><li>支持资产内嵌组件（比如前面提到的 CameraDirector）的显示与编辑。</li></ul></li><li><p>重点是：资产编辑器允许你“打开”该资产，像编辑蓝图或材质一样，实时修改其内部结构或参数，做到模板资产对用户透明且可操作。</p></li></ul><h3 id="ucameraassetfactory-ufactory" tabindex="-1"><a class="header-anchor" href="#ucameraassetfactory-ufactory"><span>UCameraAssetFactory(UFactory)</span></a></h3><p>​UFactory​ 是虚幻引擎编辑器中的基础工厂类，用于实现资产（Asset）和对象（Object）的创建和导入功能。</p><p>UCameraAssetFactory 继承于UFactory​，主要负责 UCameraAsset​ 资产在编辑器中的创建流程。</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token comment">/**</span>
<span class="line"> * Implements a factory for UCameraAsset objects.</span>
<span class="line"> */</span></span>
<span class="line"><span class="token function">UCLASS</span><span class="token punctuation">(</span>hidecategories<span class="token operator">=</span>Object<span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">UCameraAssetFactory</span> <span class="token operator">:</span> <span class="token base-clause"><span class="token keyword">public</span> <span class="token class-name">UFactory</span></span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">	<span class="token comment">// UFactory Interface</span></span>
<span class="line">	<span class="token keyword">virtual</span> UObject<span class="token operator">*</span> <span class="token function">FactoryCreateNew</span><span class="token punctuation">(</span>UClass<span class="token operator">*</span> Class<span class="token punctuation">,</span> UObject<span class="token operator">*</span> Parent<span class="token punctuation">,</span> FName Name<span class="token punctuation">,</span> EObjectFlags Flags<span class="token punctuation">,</span> UObject<span class="token operator">*</span> Context<span class="token punctuation">,</span> FFeedbackContext<span class="token operator">*</span> Warn<span class="token punctuation">)</span> <span class="token keyword">override</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">virtual</span> <span class="token keyword">bool</span> <span class="token function">ConfigureProperties</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">override</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">private</span><span class="token operator">:</span></span>
<span class="line"></span>
<span class="line">	<span class="token comment">/** The type of camera director to create for this asset. */</span></span>
<span class="line">	<span class="token function">UPROPERTY</span><span class="token punctuation">(</span>EditAnywhere<span class="token punctuation">,</span> Category<span class="token operator">=</span>Camera<span class="token punctuation">)</span></span>
<span class="line">	TSubclassOf<span class="token operator">&lt;</span>UCameraDirector<span class="token operator">&gt;</span> CameraDirectorClass<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 重新定义UCameraAsset的创建</span></span>
<span class="line">UObject<span class="token operator">*</span> <span class="token class-name">UCameraAssetFactory</span><span class="token double-colon punctuation">::</span><span class="token function">FactoryCreateNew</span><span class="token punctuation">(</span>UClass<span class="token operator">*</span> Class<span class="token punctuation">,</span> UObject<span class="token operator">*</span> Parent<span class="token punctuation">,</span> FName Name<span class="token punctuation">,</span> EObjectFlags Flags<span class="token punctuation">,</span> UObject<span class="token operator">*</span> Context<span class="token punctuation">,</span> FFeedbackContext<span class="token operator">*</span> Warn<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">	UCameraAsset<span class="token operator">*</span> NewCameraAsset <span class="token operator">=</span> <span class="token generic-function"><span class="token function">NewObject</span><span class="token generic class-name"><span class="token operator">&lt;</span>UCameraAsset<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>Parent<span class="token punctuation">,</span> Class<span class="token punctuation">,</span> Name<span class="token punctuation">,</span> Flags <span class="token operator">|</span> RF_Transactional<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">if</span> <span class="token punctuation">(</span>CameraDirectorClass<span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">{</span></span>
<span class="line">		UCameraDirector<span class="token operator">*</span> NewCameraDirector <span class="token operator">=</span> <span class="token generic-function"><span class="token function">NewObject</span><span class="token generic class-name"><span class="token operator">&lt;</span>UCameraDirector<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>NewCameraAsset<span class="token punctuation">,</span> CameraDirectorClass<span class="token punctuation">,</span> NAME_None<span class="token punctuation">,</span> RF_Transactional<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">		NewCameraAsset<span class="token operator">-&gt;</span><span class="token function">SetCameraDirector</span><span class="token punctuation">(</span>NewCameraDirector<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">return</span> NewCameraAsset<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 通过用户编辑器窗口选择获取CameraDirector类型</span></span>
<span class="line"><span class="token keyword">bool</span> <span class="token class-name">UCameraAssetFactory</span><span class="token double-colon punctuation">::</span><span class="token function">ConfigureProperties</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">	FCameraDirectorClassPicker Picker<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">	CameraDirectorClass <span class="token operator">=</span> <span class="token keyword">nullptr</span><span class="token punctuation">;</span></span>
<span class="line">	TSubclassOf<span class="token operator">&lt;</span>UCameraDirector<span class="token operator">&gt;</span> ChosenClass<span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> <span class="token keyword">bool</span> bPressedOk <span class="token operator">=</span> Picker<span class="token punctuation">.</span><span class="token function">PickCameraDirectorClass</span><span class="token punctuation">(</span>ChosenClass<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">if</span> <span class="token punctuation">(</span>bPressedOk<span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">{</span></span>
<span class="line">		CameraDirectorClass <span class="token operator">=</span> ChosenClass<span class="token punctuation">;</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line">	<span class="token keyword">return</span> bPressedOk<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>工作流程</p><ul><li>用户在编辑器中新建资产时，编辑器会查找所有注册的 UFactory​。</li><li>根据新建资产类型(需匹配 SupportedClass），调用对应的 UFactory::FactoryCreateNew​ 来创建实例。</li><li>创建后的资产实例会自动添加到内容浏览器，并打开相关编辑器。</li></ul><h3 id="uactorfactory" tabindex="-1"><a class="header-anchor" href="#uactorfactory"><span>UActorFactory</span></a></h3><p>UActorFactory 不是 UFactory的子类，它用于创建场景中的 Actor 实例的工厂类。</p><ul><li>聚焦于“世界场景中的对象创建”。</li><li>在编辑器 Windows-&gt;Place Actors 中拖拽资产到关卡时，决定如何将资产转换成 Actor 放置到关卡中.</li></ul><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token function">UCLASS</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">UGameplayCameraActorFactory</span> <span class="token operator">:</span> <span class="token base-clause"><span class="token keyword">public</span> <span class="token class-name">UActorFactory</span></span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line"></span>
<span class="line">	<span class="token function">UGameplayCameraActorFactory</span><span class="token punctuation">(</span><span class="token keyword">const</span> FObjectInitializer<span class="token operator">&amp;</span> ObjInit<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">	<span class="token comment">// UActorFactory interface.</span></span>
<span class="line">	<span class="token keyword">virtual</span> AActor<span class="token operator">*</span> <span class="token function">SpawnActor</span><span class="token punctuation">(</span>UObject<span class="token operator">*</span> InAsset<span class="token punctuation">,</span> ULevel<span class="token operator">*</span> InLevel<span class="token punctuation">,</span> <span class="token keyword">const</span> FTransform<span class="token operator">&amp;</span> InTransform<span class="token punctuation">,</span> <span class="token keyword">const</span> FActorSpawnParameters<span class="token operator">&amp;</span> InSpawnParams<span class="token punctuation">)</span> <span class="token keyword">override</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">virtual</span> <span class="token keyword">bool</span> <span class="token function">CanCreateActorFrom</span><span class="token punctuation">(</span> <span class="token keyword">const</span> FAssetData<span class="token operator">&amp;</span> AssetData<span class="token punctuation">,</span> FText<span class="token operator">&amp;</span> OutErrorMsg <span class="token punctuation">)</span> <span class="token keyword">override</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token class-name">UGameplayCameraActorFactory</span><span class="token double-colon punctuation">::</span><span class="token function">UGameplayCameraActorFactory</span><span class="token punctuation">(</span><span class="token keyword">const</span> FObjectInitializer<span class="token operator">&amp;</span> ObjInit<span class="token punctuation">)</span></span>
<span class="line">	<span class="token operator">:</span> <span class="token function">Super</span><span class="token punctuation">(</span>ObjInit<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">	<span class="token comment">// 指定要生产的Actor类型</span></span>
<span class="line">	NewActorClass <span class="token operator">=</span> <span class="token class-name">AGameplayCameraActor</span><span class="token double-colon punctuation">::</span><span class="token function">StaticClass</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">AActor<span class="token operator">*</span> <span class="token class-name">UGameplayCameraActorFactory</span><span class="token double-colon punctuation">::</span><span class="token function">SpawnActor</span><span class="token punctuation">(</span>UObject<span class="token operator">*</span> InAsset<span class="token punctuation">,</span> ULevel<span class="token operator">*</span> InLevel<span class="token punctuation">,</span> <span class="token keyword">const</span> FTransform<span class="token operator">&amp;</span> InTransform<span class="token punctuation">,</span> <span class="token keyword">const</span> FActorSpawnParameters<span class="token operator">&amp;</span> InSpawnParams<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">	AGameplayCameraActor<span class="token operator">*</span> NewActor <span class="token operator">=</span> <span class="token generic-function"><span class="token function">Cast</span><span class="token generic class-name"><span class="token operator">&lt;</span>AGameplayCameraActor<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token class-name">Super</span><span class="token double-colon punctuation">::</span><span class="token function">SpawnActor</span><span class="token punctuation">(</span>InAsset<span class="token punctuation">,</span> InLevel<span class="token punctuation">,</span> InTransform<span class="token punctuation">,</span> InSpawnParams<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">if</span> <span class="token punctuation">(</span>NewActor<span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">{</span></span>
<span class="line">		<span class="token comment">// 可以通过UCameraAsset的资源直接生成AGameplayCameraActor</span></span>
<span class="line">		<span class="token keyword">if</span> <span class="token punctuation">(</span>UCameraAsset<span class="token operator">*</span> CameraAsset <span class="token operator">=</span> <span class="token generic-function"><span class="token function">Cast</span><span class="token generic class-name"><span class="token operator">&lt;</span>UCameraAsset<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>InAsset<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">		<span class="token punctuation">{</span></span>
<span class="line">			UGameplayCameraComponent<span class="token operator">*</span> NewComponent <span class="token operator">=</span> NewActor<span class="token operator">-&gt;</span><span class="token function">GetCameraComponent</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">			NewComponent<span class="token operator">-&gt;</span>CameraReference<span class="token punctuation">.</span><span class="token function">SetCameraAsset</span><span class="token punctuation">(</span>CameraAsset<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">		<span class="token punctuation">}</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line">	<span class="token keyword">return</span> NewActor<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">bool</span> <span class="token class-name">UGameplayCameraActorFactory</span><span class="token double-colon punctuation">::</span><span class="token function">CanCreateActorFrom</span><span class="token punctuation">(</span><span class="token keyword">const</span> FAssetData<span class="token operator">&amp;</span> AssetData<span class="token punctuation">,</span> FText<span class="token operator">&amp;</span> OutErrorMsg<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">	<span class="token comment">// 在 UPlacementSubsystem 判断是否启用那个ActorFactory时，将UCameraAsset和当前ActorFactory关联起来</span></span>
<span class="line">	<span class="token keyword">if</span> <span class="token punctuation">(</span>AssetData<span class="token punctuation">.</span><span class="token function">IsValid</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">&amp;&amp;</span> AssetData<span class="token punctuation">.</span><span class="token function">IsInstanceOf</span><span class="token punctuation">(</span><span class="token class-name">UCameraAsset</span><span class="token double-colon punctuation">::</span><span class="token function">StaticClass</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">{</span></span>
<span class="line">		<span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>UGameplayCameraActorFactory 定义了 AGameplayCameraActor 的创建方式，并扩展支持从UCameraAsset来影响创建的 AGameplayCameraActor。</li><li>这个扩展非常巧妙，可以将UCameraAsset的配置应用到AGameplayCameraActor 的组件中，这样可以在编辑器中查看受当前CameAsset影响到的AGameplayCameraActor。 <ul><li>可以在编辑中拖拽这个Actor, 看到摄像机的轨迹变换。</li></ul></li><li>由UPlacementSubsystem(UEditorSubsystem)通过FindAssetFactoryFromAssetData来决策当前资源关联的Factory。</li><li>相似的实现有UGameplayCameraRigActorFactory</li></ul><h2 id="ugameplaycameracomponent" tabindex="-1"><a class="header-anchor" href="#ugameplaycameracomponent"><span>UGameplayCameraComponent</span></a></h2><p>​UGameplayCameraComponent​ 是虚幻引擎 GCS 中用于替代传统 UCameraComponent​ 的新型摄像机组件。</p><ul><li>它在自身的 Camera Evaluation context​ 上运行配置的 CameraAsset​，提供灵活且强大的摄像机控制和配置能力。</li><li>核心摄像机功能由其父类 UGameplayCameraComponentBase​负责实现，它主要提供CameraAsset​以外部参数的配置功能。</li></ul><h3 id="fcameraassetreference" tabindex="-1"><a class="header-anchor" href="#fcameraassetreference"><span>FCameraAssetReference</span></a></h3><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">UGameplayCameraComponent</span> <span class="token operator">:</span> <span class="token base-clause"><span class="token keyword">public</span> <span class="token class-name">UGameplayCameraComponentBase</span></span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">	<span class="token comment">/** The camera asset to run. */</span></span>
<span class="line">	<span class="token function">UPROPERTY</span><span class="token punctuation">(</span>BlueprintReadWrite<span class="token punctuation">,</span> EditAnywhere<span class="token punctuation">,</span> Category<span class="token operator">=</span>Camera<span class="token punctuation">,</span> meta<span class="token operator">=</span><span class="token punctuation">(</span>SequencerHideProperty<span class="token operator">=</span><span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">	FCameraAssetReference CameraReference<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">struct</span> <span class="token class-name">FCameraAssetReference</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">private</span><span class="token operator">:</span></span>
<span class="line">	<span class="token comment">/** The referenced camera asset. */</span></span>
<span class="line">	<span class="token function">UPROPERTY</span><span class="token punctuation">(</span>EditAnywhere<span class="token punctuation">,</span> Category<span class="token operator">=</span>Camera<span class="token punctuation">)</span></span>
<span class="line">	TObjectPtr<span class="token operator">&lt;</span>UCameraAsset<span class="token operator">&gt;</span> CameraAsset<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">	<span class="token comment">/** The camera asset&#39;s parameters. */</span></span>
<span class="line">	<span class="token function">UPROPERTY</span><span class="token punctuation">(</span>EditAnywhere<span class="token punctuation">,</span> Category<span class="token operator">=</span><span class="token string">&quot;&quot;</span><span class="token punctuation">,</span> meta<span class="token operator">=</span><span class="token punctuation">(</span>FixedLayout<span class="token operator">=</span><span class="token boolean">true</span><span class="token punctuation">,</span> InterpBagProperties<span class="token operator">=</span><span class="token boolean">true</span><span class="token punctuation">,</span> DisplayName<span class="token operator">=</span><span class="token string">&quot;Camera Parameters&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">	FInstancedPropertyBag Parameters<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>​FCameraAssetReference​ 是一个包含对 UCameraAsset 的引用，并管理该资产内所有关联 Camera Rig 的动态参数覆盖的结构体。类似于一个&quot;包装器&quot;。</li><li>​FCameraAssetReference​ 通过内置的动态属性容器 FInstancedPropertyBag，支持对摄像机Rig参数的灵活自定义和实时调整。</li></ul><h4 id="finstancedpropertybag" tabindex="-1"><a class="header-anchor" href="#finstancedpropertybag"><span>FInstancedPropertyBag</span></a></h4><p>强大灵活的运行时动态属性容器，打破了传统静态结构体束缚，允许动态地定义、修改、添加和读取属性。简单用法示例：</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token comment">// 定义动态属性包作为组件属性</span></span>
<span class="line"><span class="token function">UPROPERTY</span><span class="token punctuation">(</span>EditDefaultsOnly<span class="token punctuation">,</span> Category<span class="token operator">=</span>Common<span class="token punctuation">)</span></span>
<span class="line">FInstancedPropertyBag Bag<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 动态添加属性</span></span>
<span class="line">Bag<span class="token punctuation">.</span><span class="token function">AddProperties</span><span class="token punctuation">(</span><span class="token punctuation">{</span></span>
<span class="line">    <span class="token punctuation">{</span> <span class="token string">&quot;Temperature&quot;</span><span class="token punctuation">,</span> EPropertyBagPropertyType<span class="token double-colon punctuation">::</span>Float <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">{</span> <span class="token string">&quot;Count&quot;</span><span class="token punctuation">,</span> EPropertyBagPropertyType<span class="token double-colon punctuation">::</span>Int32 <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 设置属性值</span></span>
<span class="line">Bag<span class="token punctuation">.</span><span class="token function">SetValueFloat</span><span class="token punctuation">(</span><span class="token string">&quot;Temperature&quot;</span><span class="token punctuation">,</span> <span class="token number">25.0f</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">Bag<span class="token punctuation">.</span><span class="token function">SetValueInt32</span><span class="token punctuation">(</span><span class="token string">&quot;Count&quot;</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 读取属性值</span></span>
<span class="line"><span class="token keyword">auto</span> TempValue <span class="token operator">=</span> Bag<span class="token punctuation">.</span><span class="token function">GetValueFloat</span><span class="token punctuation">(</span><span class="token string">&quot;Temperature&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>TempValue<span class="token punctuation">.</span><span class="token function">IsValid</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">float</span> Temperature <span class="token operator">=</span> TempValue<span class="token punctuation">.</span><span class="token function">GetValue</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="工作机制" tabindex="-1"><a class="header-anchor" href="#工作机制"><span>工作机制</span></a></h4><p>当 CameraAsset 里的 Camera Rig 创建新的外部参数时，这些参数会暴露到 GameplayCameraComponent 的属性编辑界面，实现参数与组件属性的同步。<br> 这种同步及参数绑定主要依赖于源码工程中 Build 目录下的构建器系统（FCameraAssetBuilder, FCameraRigAssetBuilder等）生成反射及绑定代码，确保数据驱动的参数及时更新。</p><figure><img src="`+m+`" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ul><li>如果没有配置 Camera Rig的参数，这里是不会出现对应配置的</li></ul><h2 id="igameplaycamerasystemhost" tabindex="-1"><a class="header-anchor" href="#igameplaycamerasystemhost"><span>IGameplayCameraSystemHost</span></a></h2><p>IGameplayCameraSystemHost 是GCS中的核心接口，定义了作为摄像机系统宿主的对象必须遵循的行为和访问规则。</p><ul><li>提供统一的摄像机系统上下文访问协议，确保宿主能创建、销毁、更新并共享自身摄像机评估器实例（FCameraSystemEvaluator​）。</li><li>支持动态判定运行时真正的摄像机宿主角色，参考如下：</li></ul><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line">IGameplayCameraSystemHost<span class="token operator">*</span> <span class="token class-name">IGameplayCameraSystemHost</span><span class="token double-colon punctuation">::</span><span class="token function">FindActiveHost</span><span class="token punctuation">(</span>APlayerController<span class="token operator">*</span> PlayerController<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">	<span class="token keyword">if</span> <span class="token punctuation">(</span>PlayerController<span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">{</span></span>
<span class="line">		<span class="token keyword">if</span> <span class="token punctuation">(</span>PlayerController<span class="token operator">-&gt;</span>PlayerCameraManager<span class="token punctuation">)</span></span>
<span class="line">		<span class="token punctuation">{</span></span>
<span class="line">			<span class="token keyword">if</span> <span class="token punctuation">(</span>IGameplayCameraSystemHost<span class="token operator">*</span> CameraManagerHost <span class="token operator">=</span> <span class="token generic-function"><span class="token function">Cast</span><span class="token generic class-name"><span class="token operator">&lt;</span>IGameplayCameraSystemHost<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>PlayerController<span class="token operator">-&gt;</span>PlayerCameraManager<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">			<span class="token punctuation">{</span></span>
<span class="line">				<span class="token keyword">return</span> CameraManagerHost<span class="token punctuation">;</span></span>
<span class="line">			<span class="token punctuation">}</span></span>
<span class="line">		<span class="token punctuation">}</span></span>
<span class="line">		<span class="token keyword">if</span> <span class="token punctuation">(</span>AActor<span class="token operator">*</span> ViewTarget <span class="token operator">=</span> PlayerController<span class="token operator">-&gt;</span><span class="token function">GetViewTarget</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">		<span class="token punctuation">{</span></span>
<span class="line">			<span class="token keyword">if</span> <span class="token punctuation">(</span>IGameplayCameraSystemHost<span class="token operator">*</span> ViewTargetHost <span class="token operator">=</span> ViewTarget<span class="token operator">-&gt;</span><span class="token generic-function"><span class="token function">FindComponentByInterface</span><span class="token generic class-name"><span class="token operator">&lt;</span>IGameplayCameraSystemHost<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">			<span class="token punctuation">{</span></span>
<span class="line">				<span class="token keyword">return</span> ViewTargetHost<span class="token punctuation">;</span></span>
<span class="line">			<span class="token punctuation">}</span></span>
<span class="line">		<span class="token punctuation">}</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line">	<span class="token keyword">return</span> <span class="token keyword">nullptr</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>这是一个Static的方法，期待的行为是以实现IGameplayCameraSystemHost的PlayerCameraManager作为主体Host, 若没有，则通过ViewTarget来挑选。</li><li>允许有多个实现接口的Host的实例，但运行的时候只有主体Host处于激活状态。</li></ul><h3 id="interface-implementation-without-override-shared-module-​" tabindex="-1"><a class="header-anchor" href="#interface-implementation-without-override-shared-module-​"><span>Interface Implementation Without Override (Shared Module)​</span></a></h3><p>引擎中 UGameplayCameraSystemComponent、UGameplayCameraComponentBase 以及 AGameplayCamerasPlayerCameraManager 都实现了 IGameplayCameraSystemHost 接口，但接口的核心方法均未被重写，而是使用了接口提供的统一通用实现。</p><p>这种设计表现出一种独特的架构思想：</p><ul><li>接口本身构建了一个分布式的系统框架，不同的宿主（“工作站”）持有独立的摄像机系统工作环境，运行时根据状态动态选取一个宿主进行摄像机系统的控制和管理。</li><li>这种机制类似于一个分布式工作站集群，只有一台工作站被激活处理实际的请求。</li><li>各实现类根据自身职责定位，扩展特定功能和状态管理，但不会改变接口的核心行为逻辑，从而保证了系统的一致性和易维护性。</li></ul><h3 id="igameplaycamerasystemhost-的初始化" tabindex="-1"><a class="header-anchor" href="#igameplaycamerasystemhost-的初始化"><span>IGameplayCameraSystemHost 的初始化</span></a></h3><p>初始化 以实现了接口 IGameplayCameraSystemHost​ 的宿主对象为入口和载体，即只有当关卡中至少有一个此接口的实现宿主存在，初始化才会真正发生。</p><ul><li>如果关卡中不存在任何实现了该接口的宿主，则不会初始化。</li><li>宿主的接口初始化只能执行一次，IGameplayCameraSystemHost​提供了对应的实现。</li></ul><h4 id="编辑器预览模式下的初始化示例" tabindex="-1"><a class="header-anchor" href="#编辑器预览模式下的初始化示例"><span>编辑器预览模式下的初始化示例</span></a></h4><p>在空关卡中添加了一个带有 GameplayCameraComponent​ 的角色时，初始化流程的触发过程：</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token comment">// 具体流程包括：</span></span>
<span class="line">UGameplayCameraComponentBase<span class="token double-colon punctuation">::</span>TickComponent</span>
<span class="line">UGameplayCameraComponentBase<span class="token double-colon punctuation">::</span>AutoManageEditorPreviewEvaluator <span class="token comment">//WITH_EDITOR</span></span>
<span class="line">UGameplayCameraComponentBase<span class="token double-colon punctuation">::</span>EnsureCameraSystemHost  <span class="token comment">// 确保初始化只完成一次</span></span>
<span class="line">	IGameplayCameraSystemHost<span class="token double-colon punctuation">::</span>InitializeCameraSystem</span>
<span class="line"></span>
<span class="line"><span class="token comment">// 由于编辑器预览模式无 PlayerController 存在，组件本身成为当前激活的宿主。</span></span>
<span class="line"><span class="token function">ActivateCameraEvaluationContext</span><span class="token punctuation">(</span><span class="token keyword">nullptr</span><span class="token punctuation">,</span> <span class="token keyword">this</span><span class="token punctuation">,</span> EGameplayCameraComponentActivationMode<span class="token double-colon punctuation">::</span>Push<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="运行时模式-编辑器运行或真实游戏-下的初始化示例" tabindex="-1"><a class="header-anchor" href="#运行时模式-编辑器运行或真实游戏-下的初始化示例"><span>运行时模式（编辑器运行或真实游戏）下的初始化示例</span></a></h4><p>关卡默认创建挂载 GameplayCameraComponent 的角色， 运行此关卡。</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line">AActor<span class="token double-colon punctuation">::</span>Beginplay</span>
<span class="line">UGameplayCameraComponentBase<span class="token double-colon punctuation">::</span>ActivateCameraForPlayerController</span>
<span class="line">UGameplayCameraComponentBase<span class="token double-colon punctuation">::</span>EnsureCameraSystemHost   <span class="token comment">// 确保初始化只完成一次</span></span>
<span class="line">	IGameplayCameraSystemHost<span class="token double-colon punctuation">::</span>InitializeCameraSystem</span>
<span class="line"></span>
<span class="line"><span class="token comment">// PlayerController 存在, 但其 PlayerCameraManager 未被替换为支持 GCS 的实现，组件本身成为当前激活的宿主。</span></span>
<span class="line"><span class="token function">ActivateCameraEvaluationContext</span><span class="token punctuation">(</span>PlayerController<span class="token punctuation">,</span> <span class="token keyword">this</span><span class="token punctuation">,</span> EGameplayCameraComponentActivationMode<span class="token double-colon punctuation">::</span>Push<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="ugameplaycameracomponentbase" tabindex="-1"><a class="header-anchor" href="#ugameplaycameracomponentbase"><span>UGameplayCameraComponentBase</span></a></h3><p>当游戏中 PlayerController 的 PlayerCameraManager 被替换为支持 GCS 的 AGameplayCamerasPlayerCameraManager​ 类型后，所有挂载了 UGameplayCameraComponentBase​ 的组件将放弃自身独立持有的摄像机系统评估器，转由 PlayerCameraManager 统一管理。</p><p>具体过程（代码片段核心）：</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line">IGameplayCameraSystemHost<span class="token operator">*</span> PlayerControllerHost <span class="token operator">=</span> <span class="token keyword">nullptr</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>bSetAsViewTarget <span class="token operator">&amp;&amp;</span> PlayerController<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    PlayerControllerHost <span class="token operator">=</span> <span class="token generic-function"><span class="token function">Cast</span><span class="token generic class-name"><span class="token operator">&lt;</span>IGameplayCameraSystemHost<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>PlayerController<span class="token operator">-&gt;</span>PlayerCameraManager<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>PlayerControllerHost<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">HasCameraSystem</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">{</span></span>
<span class="line">		<span class="token function">DestroyCameraSystem</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 销毁自身的 CameraSystemEvaluator</span></span>
<span class="line">	<span class="token punctuation">}</span> </span>
<span class="line">    <span class="token function">ActivateCameraEvaluationContext</span><span class="token punctuation">(</span>PlayerController<span class="token punctuation">,</span> PlayerControllerHost<span class="token punctuation">,</span> ActivationMode<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">else</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// 旧版 PlayerCameraManager 或无 PlayerController，组件独立运作</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">void</span> <span class="token class-name">UGameplayCameraComponentBase</span><span class="token double-colon punctuation">::</span><span class="token function">ActivateCameraEvaluationContext</span><span class="token punctuation">(</span>APlayerController<span class="token operator">*</span> PlayerController<span class="token punctuation">,</span> IGameplayCameraSystemHost<span class="token operator">*</span> Host<span class="token punctuation">,</span> EGameplayCameraComponentActivationMode ActivationMode<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">	TSharedPtr<span class="token operator">&lt;</span>FCameraSystemEvaluator<span class="token operator">&gt;</span> HostEvaluator <span class="token operator">=</span> Host<span class="token operator">-&gt;</span><span class="token function">GetCameraSystemEvaluator</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	FCameraEvaluationContextStack<span class="token operator">&amp;</span> ContextStack <span class="token operator">=</span> HostEvaluator<span class="token operator">-&gt;</span><span class="token function">GetEvaluationContextStack</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">switch</span> <span class="token punctuation">(</span>ActivationMode<span class="token punctuation">)</span></span>
<span class="line">	<span class="token punctuation">{</span></span>
<span class="line">		<span class="token keyword">case</span> EGameplayCameraComponentActivationMode<span class="token double-colon punctuation">::</span>Push<span class="token operator">:</span></span>
<span class="line">			ContextStack<span class="token punctuation">.</span><span class="token function">PushContext</span><span class="token punctuation">(</span>EvaluationContext<span class="token punctuation">.</span><span class="token function">ToSharedRef</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">			<span class="token keyword">break</span><span class="token punctuation">;</span></span>
<span class="line">		<span class="token keyword">default</span><span class="token operator">:</span></span>
<span class="line">			<span class="token function">ensure</span><span class="token punctuation">(</span><span class="token boolean">false</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">			<span class="token keyword">break</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>组件主动销毁自己的 CameraSystemEvaluator​，并将摄像机评估上下文激活权移交给 PlayerCameraManager​ 的评估器上下文堆栈(ContextStack​)。</li><li>​AGameplayCamerasPlayerCameraManager​ 作为全局管理者，通过 ContextStack 统一调度管理若干摄像机评估上下文，最终决定玩家视角。</li><li><strong>如果不存在支持的 PlayerCameraManager，组件自行作为独立宿主运行，管理自身摄像机轨迹。</strong></li></ul><h3 id="ugameplaycamerasystemcomponent" tabindex="-1"><a class="header-anchor" href="#ugameplaycamerasystemcomponent"><span>UGameplayCameraSystemComponent</span></a></h3><p>在虚幻 5.6的GCS实现中，UGameplayCameraSystemComponent 是独立运行的Host， 并不受这里的PlayerCameraManager管理，只和当前ViewTarget有关。</p><ul><li>只有挂载这个组件的AGameplayCameraSystemActor可以创建蓝图子类。</li><li>UGameplayCameraSystemComponent 需要配置关联的PlayerController, 才能正常完成接口初始化。</li><li>UGameplayCameraSystemComponent 是通过GCS来进行计算的摄像机视角的，没有配置的话会是一个固定视角。 <ul><li>可以激活Global和Visual层级的Game Rig, 但是实测下来摄像机视角没有变化，待后续继续确认原因。</li><li>最大的问题有两个（等待后续解决）： <ul><li>重启编辑器关卡后，CameraSystemEvaluator的Owner 弱指针检查报错。 导致 DebugDraw 无法正常运行。</li><li>这个组件可以在Global和Visual层添加CameraRig， 但是测试下来未生效。原因未知。</li></ul></li></ul></li></ul><div class="hint-container warning"><p class="hint-container-title">Warning</p><p>在5.6版本中不建议使用 UGameplayCameraSystemComponent相关的内容，测试下来感觉还在开发中，依然存在不少问题。</p></div>`,74))])}const g=p(k,[["render",v],["__file","03-gcs-editor-and-host.html.vue"]]),h=JSON.parse('{"path":"/GameEngine/Unreal/Camera/03-gcs-editor-and-host.html","title":"GCS Editor Extensions & IGameplayCameraSystemHost","lang":"en-US","frontmatter":{"date":"2025-07-08T10:00:00.000Z","tag":["Unreal Engine","Camera","GCS"]},"git":{"createdTime":1782391349000,"updatedTime":1782391349000,"contributors":[{"name":"BanMing","username":"BanMing","email":"ban-ming@foxmail.com","commits":1,"url":"https://github.com/BanMing"},{"name":"Claude Opus 4.7","username":"Claude Opus 4.7","email":"noreply@anthropic.com","commits":1,"url":"https://github.com/Claude Opus 4.7"}]},"readingTime":{"minutes":10.75,"words":3224},"filePathRelative":"GameEngine/Unreal/Camera/03-gcs-editor-and-host.md","localizedDate":"July 8, 2025","excerpt":"\\n<p><a href=\\"/GameEngine/Unreal/Camera/02-getting-started-gcs.html\\" target=\\"_blank\\">第一篇文章</a>中我们简单介绍了GCS怎么激活，以及怎么在编辑器中利用它的工具链去构建对应行为的摄像机。</p>\\n<p>这篇文章主要介绍工具链中的UCameraAsset是怎么可以创建模版资源的，以及它是怎么指定CameraDirector的。</p>\\n<p>文章的后面部分我们还会对GCS的核心接口 IGameplayCameraSystemHost 进行介绍。</p>\\n<h2>UPROPERTY(Instanced)</h2>"}');export{g as comp,h as data};
